window.__QUIZ_DATA__=[{"id":"theory>Geography>2012>Theory 1>1>a","subject":"Geography","year":"2012","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract on a scale of 1:50,000 and answer the following questions:    In your answer book, draw an outline of the area marked PQRS on a new scale of 1:25,000","images":[],"marking_scheme":"The outline of map of the area is marked PQRS  |PQ| = 16cm   |PS| = 20cm","marks":"5","difficulty":"3"},{"id":"theory>Geography>2012>Theory 1>1>b","subject":"Geography","year":"2012","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"In your new outline; insert and name: (i) River lamurdi; (ii) JALINGO; (iii) the 700ft contour line to the South of the area marked PQRS; (iv) a lake","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2012>Theory 1>1>c>i","subject":"Geography","year":"2012","type":"Theory","sub_label":"i","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Using the whole map extract:   State three economic activities in the mapped area giving reasons for your answer;","images":[],"marking_scheme":"- Fishing, by the presence of a big river   -Farming, by the scattered cultivation   - Trading, by presence of market at Jalingo","marks":"3","difficulty":"2"},{"id":"theory>Geography>2012>Theory 1>1>c>ii","subject":"Geography","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"describe the relief of the mapped area.","images":[],"marking_scheme":"The western part of the area is lower than other parts. The highest point is North East with a height above 2700ft while the lowest part is North West with height less than 600ft. There are highlands at the Northeast, East and Southeast but the west and central parts of the area are generally uneven or undulating.    There are few round topped hills which are small in size at the southwest and Northwest of the mapped area and there are also valley in the central and western part. Some cliffs can also be seen at the South-east.","marks":"2","difficulty":"2"},{"id":"theory>Geography>2012>Theory 1>2>a>i","subject":"Geography","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Study the climatic data below and use it to answer the questions that follow:  Month J F M A M J J A S O N DTemperature (oC) 21 21 20 17 15 12 12 13 14 18 18 20Rainfall (mm) 18 17 20 39 48 90 112 90 56 47 30 25    Calculate the annual range of temperature;","images":[],"marking_scheme":"Annual Range of temperature = Highest Temperature - Lowest temperature= 21oC - 12oC = 9oC","marks":"5","difficulty":"2"},{"id":"theory>Geography>2012>Theory 1>2>a>ii","subject":"Geography","year":"2012","type":"Theory","sub_label":"ii","group":"FINAL","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"the mean annual temperature","images":[],"marking_scheme":"MeanAnnualTemperature=Total Annual Temperature12    =20112=16.75oC","marks":"5","difficulty":"1"},{"id":"theory>Geography>2012>Theory 1>2>b","subject":"Geography","year":"2012","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Use the climate data to draw a combined rainfall and temperature graph for the station","images":["data:image/png;base64,"],"marking_scheme":"Combined Rainfall and Temperature graph      Scale: Let; 2cm represent 20mm on rainfall 2cm rep. 50C on temperature axis   2cm rep 1 mth on x-axis","marks":"8","difficulty":"2"},{"id":"theory>Geography>2012>Theory 1>2>c","subject":"Geography","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Identify the climatic type in (b) above","images":[],"marking_scheme":"Mediterranean climate","marks":"2","difficulty":"1"},{"id":"theory>Geography>2012>Theory 1>3>a","subject":"Geography","year":"2012","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"With the aid of diagram, describe the Greek system of climatic classification.","images":["data:image/png;base64,"],"marking_scheme":"This sytem emphasizes on temperature and makes use of already established boundaries; 0, 23 1/2 N and S of the equator. It makes out torrid, temperature and frigid zones. This system also approves the temperate region as the suitable climate.","marks":"15","difficulty":"3"},{"id":"theory>Geography>2012>Theory 1>3>b","subject":"Geography","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Identify three criticisms of the Greek system of climatic classification.","images":[],"marking_scheme":"- It emphasizes only one parameter i.e Temperature   - It does not quantify   - It does not recognise the humid and desert climates","marks":"5","difficulty":"2"},{"id":"theory>Geography>2012>Theory 1>4>a","subject":"Geography","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Name any four planets in the solar system","images":[],"marking_scheme":"- Jupiter   - Uranus   - Earth   - Mars","marks":"5","difficulty":"1"},{"id":"theory>Geography>2012>Theory 1>4>b>i","subject":"Geography","year":"2012","type":"Theory","sub_label":"i","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"With the aid of appropriate diagram, explain three proofs to show that the earth is spherical in shape.","images":[],"marking_scheme":"- Circumnavigation of the Earth. The circumnavigation by earth explorers such as Ferdinand Magellan and his crew travelled round the world by moving in a direction proved beyond doubt that the earth is spherical. They did not encounter any abrupt edge which they have fallen into. This shows that the earth is spherical in shape.   - Sunrise and Sunset: The sun rises and sets at different times and places. It is seen first in the East and sets in the West. If the world was flat, sunrise and sunset would occur simultaneously.","marks":"5","difficulty":"3"},{"id":"theory>Geography>2012>Theory 1>4>b>ii","subject":"Geography","year":"2012","type":"Theory","sub_label":"ii","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"With the aid of appropriate diagram, explain three proofs to show that the earth is spherical in shape.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"5","difficulty":"3"},{"id":"theory>Geography>2012>Theory 1>4>b>iii","subject":"Geography","year":"2012","type":"Theory","sub_label":"iii","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"With the aid of appropriate diagram, explain three proofs to show that the earth is spherical in shape.","images":["data:image/png;base64,"],"marking_scheme":"Ship's Visibility:   If the earth were to be flat, a ship on water would appear or disappear at the same time, but because the earth is sherical, when a ship appears over a distance horizon, the observer sees the topmost part before seeing the hull.   As times goes by, the entire ship appears.","marks":"5","difficulty":"3"},{"id":"theory>Geography>2012>Theory 1>5>a>i","subject":"Geography","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"With the aid of diagram, describe the following:    sea breeze;","images":["data:image/png;base64,"],"marking_scheme":"The sea breeze results from a differential rate of heating and cooling of land and water bodies. It operates at day time.   This results into differential pressure belts over land and water bodies during the day.   The air over the land rises and cool currents of air moves from the sea to take the position of rising air on land.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2012>Theory 1>5>a>ii","subject":"Geography","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"With the aid of diagram, describe the following: land breeze","images":["data:image/png;base64,"],"marking_scheme":"At night, the land cools faster than water bodies, therefore various pressure belts are formed i.e low pressure on water bodies and higher pressure on land. The warm air over sea rises and cool currents of the air moves from the land to take the position of the rising air around from water.","marks":"7","difficulty":"2"},{"id":"theory>Geography>2012>Theory 1>5>b","subject":"Geography","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"State two factors that influence the salinity of oceans","images":[],"marking_scheme":"- Rate of evaporation   - Size of water body","marks":"5","difficulty":"1"},{"id":"theory>Geography>2012>Theory 1>6>a","subject":"Geography","year":"2012","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Define vulcanicity","images":[],"marking_scheme":"Vulcanicity is an occurence whereby molten magm together with associated solid and gaseous materials are ejected out of the earth crust.","marks":"1","difficulty":"1"},{"id":"theory>Geography>2012>Theory 1>6>b>i","subject":"Geography","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Describe the characteristics and mode of formation of any one of the following features:    - dyke;","images":[],"marking_scheme":"It is a highly inclined sheet of igneous rock which is very resistant and takes advantage of fault lines. It is an intrusive rock which is formed from motten magma beneath earth forced through cracks and sometimes do not reach the surface but solidify along vertical fissures to form walls or cracks.","marks":"5","difficulty":"3"},{"id":"theory>Geography>2012>Theory 1>6>b>ii","subject":"Geography","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Describe the characteristics and mode of formation of any one of the following features:Composite cone","images":[],"marking_scheme":"- Composite volcanoes are made up of alternating layers of lava and ash (other volcanoes just consist of lava).  - They are usually found at destructive or compressional boundaries.  -  The eruptions from these volcanoes may be a pyroclastic flow rather than a lava flow.","marks":"5","difficulty":"3"},{"id":"theory>Geography>2012>Theory 1>6>c","subject":"Geography","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"In what three ways are volcanic rocks important to man?","images":[],"marking_scheme":"- It serves as a source of minerals   - It is a source of fertile soils for agricultural purposes   - It serves as tourist centres","marks":"5","difficulty":"2"},{"id":"theory>Geography>2012>Theory 1>7>a","subject":"Geography","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"List any four sources of water","images":[],"marking_scheme":"- Rainfall   - Boreholes and wells   - Springs   - Oceans and Seas","marks":"10","difficulty":"1"},{"id":"theory>Geography>2012>Theory 1>7>b","subject":"Geography","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Describe any four ways in which water is useful as an environmental source","images":[],"marking_scheme":"- Sources of minerals e.g Diamond   - Domestic uses e.g drinking, washing, etc.   - Industrial uses E.g engine cooling   - Recreation E.g swimming","marks":"5","difficulty":"2"},{"id":"theory>Geography>2012>Theory 1>7>c","subject":"Geography","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Highlight any three major problems resulting from water pollution","images":[],"marking_scheme":"- Extinction (death) of aquatic organisms   - Ecological Imbalance   - Unavailability of water for agricultural purposes","marks":"5","difficulty":"2"},{"id":"theory>Geography>2012>Theory 1>8>a","subject":"Geography","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Name any four natural hazards","images":[],"marking_scheme":"- Flood   - Landslide   - Drought   - Hurricane","marks":"10","difficulty":"1"},{"id":"theory>Geography>2012>Theory 1>8>b","subject":"Geography","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Highlight any three effects of air pollution","images":[],"marking_scheme":"- It causes acid rain   - It leads to respiratory illnesses   - It depletes the ozone layers","marks":"5","difficulty":"2"},{"id":"theory>Geography>2012>Theory 1>8>c","subject":"Geography","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"In what three ways can air pollution be controlled?","images":[],"marking_scheme":"- Fumes from Industries should be treated before being let off into the atmosphere   - Industries should be sited far away from people's residence   - Bush burning should be discouraged","marks":"5","difficulty":"2"},{"id":"theory>Geography>2012>Theory 2>1>a","subject":"Geography","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Highlight any four differences between urban and rural settlements","images":[],"marking_scheme":"Differences Between urban and Rural Settlements   Urban settlement Rural settlement (i) presence of social amenities Absence of social amenities(ii) More prone to pollution Less prone to pollution (iii) Well developed layouts Less developed layouts (iv) Dense populated Less-densely populated","marks":"10","difficulty":"2"},{"id":"theory>Geography>2012>Theory 2>1>b","subject":"Geography","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Outline any four favourable conditions for the growth of settlements","images":[],"marking_scheme":"- Adequate water supply   - Absence of disasters   - Government policy   - Presence of social amenities","marks":"10","difficulty":"2"},{"id":"theory>Geography>2012>Theory 2>2>a>i","subject":"Geography","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"State three advantages air transport","images":[],"marking_scheme":"- It is the fastest transport means   - Its course/path does not need maintenance   - It is convenient and comfortable","marks":"5","difficulty":"1"},{"id":"theory>Geography>2012>Theory 2>2>a>ii","subject":"Geography","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"State two disadvantages of air transportation","images":[],"marking_scheme":"- It is expensive   - It's accidents are usually fatal","marks":"5","difficulty":"1"},{"id":"theory>Geography>2012>Theory 2>2>b","subject":"Geography","year":"2012","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Highlight five roles of road transportation in the promotion of economic development","images":[],"marking_scheme":"- Access to natural resources   - Movement of both humans and goods and services   - Tourism development   - Generation of employment   - Strengthens National Integration and Interaction","marks":"10","difficulty":"2"},{"id":"theory>Geography>2012>Theory 2>3>a","subject":"Geography","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Describe any three factors responsible for the dominance of light industries in developing countries","images":[],"marking_scheme":"- Presence of unskilled labour   - Inadequate technology   - Availability of local raw materials","marks":"10","difficulty":"2"},{"id":"theory>Geography>2012>Theory 2>3>b","subject":"Geography","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Highlight any four advantages of the concentration of industries in urban areas of developing countries","images":[],"marking_scheme":"- Availability of banking service   - It encourages development of subsidiary industries   - It encourages development of skilled man-power   - It improves the standard of living of the people","marks":"5","difficulty":"2"},{"id":"theory>Geography>2012>Theory 2>3>c","subject":"Geography","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Outline any three disadvantages of the concentration of industries in the urban areas of developing countries","images":[],"marking_scheme":"- Inadequate technological know-how   - Environmental pollution   - Inadequate housing","marks":"5","difficulty":"2"},{"id":"theory>Geography>2012>Theory 2>4>a","subject":"Geography","year":"2012","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria. On the map, show the name:  (i) a delta; (ii) a man-made lake; (iii) a confluence town; (iv) the Jos Platea.","images":["data:image/png;base64,"],"marking_scheme":"(i) A delta (Niger Delta)  (ii) A man-made lake (kainyi)   (iii) A confluence town (Lokoja)  (iv) The Jos Plateau","marks":"10","difficulty":"3"},{"id":"theory>Geography>2012>Theory 2>4>b","subject":"Geography","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"Outline any three physical factors that limit the use of rivers for transportation in Nigeria","images":[],"marking_scheme":"- Presence of debris   - Presence of water weeds   - Narrow channels and gorges","marks":"5","difficulty":"2"},{"id":"theory>Geography>2012>Theory 2>4>c","subject":"Geography","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"Highlight three possible solutions to the limiting factors mentioned in 4(b) above","images":[],"marking_scheme":"- Construction of dams and canals   - Building of locks   - Clearing of debris","marks":"5","difficulty":"2"},{"id":"theory>Geography>2012>Theory 2>5>a","subject":"Geography","year":"2012","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : VEGETATION","question":"Draw an outline map of Nigeria. On the map, show the name: (i) Abuja; (ii) three savanna vegetation belts","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2012>Theory 2>5>b","subject":"Geography","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"State four ways in which the forest vegetation of Nigeria contributes to her economy.","images":[],"marking_scheme":"- Provision of Foreign exchange   - Provision of employment   - Forest fruits serve as food   - Source of tourism and wildlife","marks":"5","difficulty":"2"},{"id":"theory>Geography>2012>Theory 2>5>c","subject":"Geography","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"Highlight any two problems that hinders the exploitation of forest vegetation in Nigeria","images":[],"marking_scheme":"- Depletion of the natural vegetation   - Soil erosion/Leaching","marks":"5","difficulty":"2"},{"id":"theory>Geography>2012>Theory 2>6>a","subject":"Geography","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"Highlight five problems of development of the Cross River Basin","images":[],"marking_scheme":"- Heavy flooding   - Shortage of adequate potable water   - Increased Salinity of mangrove swamps   - Poor transportation network   - The dispersed nature of settlements","marks":"5","difficulty":"3"},{"id":"theory>Geography>2012>Theory 2>6>b","subject":"Geography","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"In what five ways can these problems be solved?","images":[],"marking_scheme":"- Control measures should be implemented against soil erosion   - Improvements should be made in the transport network   - Economic empowerment   - Legislation should be made on oil companies for proper disposal of effluents   - Bridges should be constructed across water-logged and swampy areas.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2012>Theory 2>7>a","subject":"Geography","year":"2012","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw a map of West Africa. On it, show and name:   (i) One french speaking country; (ii) one English speaking country; (iii) the capital of the countries shown in 7(a)(i) and 7(a)(ii) above.","images":["data:image/png;base64,"],"marking_scheme":"(i) French speaking country - Togo   (ii) English speaking country - Ghana   (iii) - Togo - Lome   - Ghana - Accra","marks":"10","difficulty":"3"},{"id":"theory>Geography>2012>Theory 2>7>b","subject":"Geography","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"State three objectives of the Economic Community of West African States (ECOWAS).","images":[],"marking_scheme":"- To promote trading among member states   - To contribute to a common fund   - To ensure cultural co-operation among member states","marks":"5","difficulty":"1"},{"id":"theory>Geography>2012>Theory 2>7>c","subject":"Geography","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"Highlight three problems hindering the achievement of the objectives of the Economic Community of West African States (ECOWAS)","images":[],"marking_scheme":"- Language barrier   - Poor communication and transportation   - Smuggling/sabotage (economic)","marks":"5","difficulty":"3"},{"id":"theory>Geography>2012>Theory 2>8>a","subject":"Geography","year":"2012","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw an outline map of Africa. On the map, locate and name:   (i) longitudes 0o and 20oE; (ii) latitudes 0o and 35oS; (iii) the Atlas Mountains; (iv) one man-made lake along the River Nile.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"2"},{"id":"theory>Geography>2012>Theory 2>8>b","subject":"Geography","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Explain five ways in which African rivers are important","images":[],"marking_scheme":"- They are source of food like sea foods   - Employment opportunities   - Electricity generation   - Domestic and Industrial uses  - Transportation and carriage","marks":"10","difficulty":"2"},{"id":"theory>Geography>2012>Theory 2>9>a","subject":"Geography","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Describe lumbering in aire under the following headings:    favourable factors;","images":[],"marking_scheme":"- Labour is cheap   - Equatorial climate is favourable   - Mill industries are efficient   - High demand for timber   - Economic trees are present","marks":"8","difficulty":"2"},{"id":"theory>Geography>2012>Theory 2>9>b","subject":"Geography","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Describe lumbering in aire under the following headings:  problems of exploitations;","images":[],"marking_scheme":"- Inadequate capital   - Transportation is expensive   - Gradual depletion of economic trees   - Difficulty in felling trees   - Difficulty in locating mature trees because of the density of the forest.","marks":"7","difficulty":"2"},{"id":"theory>Geography>2012>Theory 2>9>c","subject":"Geography","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Describe lumbering in aire under the following headings:  contribute to the economy","images":[],"marking_scheme":"- Source of revenue   - Source of foreign exchange   - Job opportunities   - Construction of boats and Canoes","marks":"5","difficulty":"2"}];